#!/usr/bin/env python3\n\nimport sys\nfrom pathlib import Path\n\n# Add current directory to path\ncurrent_dir = Path(__file__).parent\nif str(current_dir) not in sys.path:\n    sys.path.insert(0, str(current_dir))\n\ndef test_cognitive_system_demo():\n    \"\"\"Demonstrate the S1 vs S2 cognitive system in action.\"\"\"\n    \n    print(\"\\n🧠 FLEE COGNITIVE SYSTEM DEMONSTRATION\")\n    print(\"=\" * 50)\n    \n    # Import Flee components\n    from flee.SimulationSettings import SimulationSettings\n    from flee.flee import Person, Location\n    from flee import moving\n    \n    print(\"✅ Imports successful\")\n    \n    # Initialize settings first\n    SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n    print(\"✅ Settings loaded\")\n    \n    # Enable cognitive system\n    SimulationSettings.move_rules[\"TwoSystemDecisionMaking\"] = True\n    SimulationSettings.move_rules[\"conflict_threshold\"] = 0.4\n    print(\"✅ Cognitive system enabled\")\n    \n    print(\"\\n📊 COGNITIVE PRESSURE DEMONSTRATION\")\n    print(\"-\" * 40)\n    \n    # Test different scenarios\n    scenarios = [\n        {\"name\": \"Peaceful\", \"conflict\": 0.0, \"connections\": 3},\n        {\"name\": \"Low Conflict\", \"conflict\": 0.3, \"connections\": 3},\n        {\"name\": \"High Conflict\", \"conflict\": 0.8, \"connections\": 3},\n        {\"name\": \"High Conflict + Connected\", \"conflict\": 0.8, \"connections\": 8},\n    ]\n    \n    print(f\"{'Scenario':<25} {'Conflict':<8} {'Connections':<11} {'Pressure':<8}\")\n    print(\"-\" * 55)\n    \n    for scenario in scenarios:\n        # Create location with conflict\n        location = Location(\"TestLoc\", 0, 0, 1000)\n        location.conflict_intensity = {1: scenario[\"conflict\"]}\n        location.time_of_conflict = 0 if scenario[\"conflict\"] > 0 else -1\n        \n        # Create agent\n        agent = Person(location, attributes={\"connections\": scenario[\"connections\"]})\n        \n        # Calculate pressure\n        pressure = agent.calculate_cognitive_pressure(time=1)\n        \n        print(f\"{scenario['name']:<25} {scenario['conflict']:<8.1f} {scenario['connections']:<11} {pressure:<8.3f}\")\n    \n    print(\"\\n🎯 SYSTEM 2 CAPABILITY DEMONSTRATION\")\n    print(\"-\" * 40)\n    \n    connection_levels = [0, 1, 2, 3, 4, 5, 8]\n    \n    print(f\"{'Connections':<12} {'S2 Capable'}\")\n    print(\"-\" * 25)\n    \n    location = Location(\"TestLoc\", 0, 0, 1000)\n    \n    for connections in connection_levels:\n        agent = Person(location, attributes={\"connections\": connections})\n        s2_capable = agent.get_system2_capable()\n        print(f\"{connections:<12} {s2_capable}\")\n    \n    print(\"\\n🔄 COGNITIVE SWITCHING DEMONSTRATION\")\n    print(\"-\" * 40)\n    \n    test_cases = [\n        {\"name\": \"S1: Low connections\", \"connections\": 1, \"conflict\": 0.2},\n        {\"name\": \"S1: No conflict\", \"connections\": 6, \"conflict\": 0.0},\n        {\"name\": \"S2: High conflict + connected\", \"connections\": 6, \"conflict\": 0.8},\n        {\"name\": \"Borderline case\", \"connections\": 4, \"conflict\": 0.5},\n    ]\n    \n    print(f\"{'Test Case':<25} {'Connections':<11} {'Conflict':<8} {'Pressure':<8} {'System':<6} {'Move Chance'}\")\n    print(\"-\" * 75)\n    \n    for case in test_cases:\n        # Create location with conflict\n        location = Location(\"TestLoc\", 0, 0, 1000)\n        location.conflict_intensity = {1: case[\"conflict\"]}\n        location.time_of_conflict = 0 if case[\"conflict\"] > 0 else -1\n        \n        # Create agent\n        agent = Person(location, attributes={\"connections\": case[\"connections\"]})\n        \n        # Calculate pressure\n        pressure = agent.calculate_cognitive_pressure(time=1)\n        \n        # Test move chance calculation\n        movechance, system2_active = moving.calculateMoveChance(agent, False, 1)\n        \n        system = \"S2\" if system2_active else \"S1\"\n        \n        print(f\"{case['name']:<25} {case['connections']:<11} {case['conflict']:<8.1f} {pressure:<8.3f} {system:<6} {movechance:<10.3f}\")\n    \n    print(\"\\n🎉 DEMONSTRATION COMPLETE!\")\n    print(\"\\n📋 Key Findings:\")\n    print(\"   ✅ Cognitive pressure increases with conflict and connections\")\n    print(\"   ✅ System 2 requires ≥3 social connections\")\n    print(\"   ✅ S1 and S2 produce different move chances\")\n    print(\"   ✅ Agents switch dynamically based on conditions\")\n    print(\"\\n🚀 The S1/S2 cognitive system is working perfectly!\")\n\nif __name__ == \"__main__\":\n    test_cognitive_system_demo()\n"